mapper.select:
SELECT bp.id, bp.category, bp.title, bp.content, u.display_name AS author, bp.author_id, bp.views, bp.likes, bp.comment_count, bp.pinned, bp.created_at, bp.updated_at FROM board_posts bp JOIN users u ON u.user_id = bp.author_id
AND bp.category = #{category}
AND ( bp.title LIKE CONCAT('%', #{searchQuery}, '%') OR u.display_name LIKE CONCAT('%', #{searchQuery}, '%') )
ORDER BY bp.pinned DESC,
bp.views DESC bp.likes DESC bp.comment_count DESC bp.created_at DESC
LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*) FROM board_posts bp JOIN users u ON u.user_id = bp.author_id
AND bp.category = #{category}
AND ( bp.title LIKE CONCAT('%', #{searchQuery}, '%') OR u.display_name LIKE CONCAT('%', #{searchQuery}, '%') )

SELECT COUNT(*)
FROM board_post_likes
WHERE user_id = #{userId}
  AND post_id = #{postId}

mapper.delete:
DELETE FROM board_post_likes
WHERE user_id = #{userId}
  AND post_id = #{postId}

